function NetworkDiagram() {
  const layers = [
    [
      [80, 85],
      [80, 205],
    ],
    [
      [205, 85],
      [205, 145],
      [205, 205],
    ],
    [
      [330, 85],
      [330, 145],
      [330, 205],
    ],
    [[455, 145]],
  ];

  return (
    <svg
      viewBox="0 0 540 290"
      className="h-full min-h-[290px] w-full"
      aria-hidden="true"
    >
      {layers
        .slice(0, -1)
        .flatMap((layer, layerIndex) =>
          layer.flatMap(([x1, y1]) =>
            layers[layerIndex + 1].map(([x2, y2], index) => (
              <line
                key={`${layerIndex}-${x1}-${y1}-${index}`}
                x1={x1}
                y1={y1}
                x2={x2}
                y2={y2}
                stroke="var(--color-primary)"
                strokeOpacity={index % 2 === 0 ? 0.42 : 0.16}
                strokeWidth="1"
              />
            )),
          ),
        )}
      {layers.flatMap((layer, layerIndex) =>
        layer.map(([cx, cy], index) => (
          <circle
            key={`${layerIndex}-${index}`}
            cx={cx}
            cy={cy}
            r={layerIndex === 3 ? 10 : 8}
            fill="var(--color-background)"
            stroke={
              layerIndex === 3
                ? "var(--color-primary)"
                : "var(--color-outline-dark)"
            }
            strokeWidth="1.5"
          />
        )),
      )}
      {["input", "hidden", "hidden", "output"].map((label, index) => (
        <text
          key={label + index}
          x={layers[index][0][0]}
          y="245"
          textAnchor="middle"
          className="fill-on-surface-variant font-mono text-[9px]"
        >
          {label}
        </text>
      ))}
    </svg>
  );
}

